// LCG parameters for random number generation
#define LCG_M 9223372036854775808ULL // 2^63
#define LCG_A 2806196910506780709ULL
#define LCG_C 1ULL

// Function to generate a random double using LCG
inline double LCG_random_double_kernel(uint64_t * seed) {
    *seed = (LCG_A * (*seed) + LCG_C) % LCG_M;
    return (double) (*seed) / (double) LCG_M;
}

// Function to perform binary search on the nuclide energy grid
inline long grid_search_nuclide_kernel( long n, double quarry, __global const NuclideGridPoint * A, long low, long high) {
    long lowerLimit = low;
    long upperLimit = high;
    long examinationPoint;
    long length = upperLimit - lowerLimit;

    while (length > 1) {
        examinationPoint = lowerLimit + (length / 2);

        if (A[examinationPoint].energy > quarry)
            upperLimit = examinationPoint;
        else
            lowerLimit = examinationPoint;

        length = upperLimit - lowerLimit;
    }
    return lowerLimit;
}

// Function to perform binary search on the unionized energy grid
inline long grid_search_kernel( long n, double quarry, __global const double * A) {
    long lowerLimit = 0;
    long upperLimit = n - 1;
    long examinationPoint;
    long length = upperLimit - lowerLimit;

    while (length > 1) {
        examinationPoint = lowerLimit + (length / 2);

        if (A[examinationPoint] > quarry)
            upperLimit = examinationPoint;
        else
            lowerLimit = examinationPoint;

        length = upperLimit - lowerLimit;
    }
    return lowerLimit;
}

// Calculates the microscopic cross section for a given nuclide & energy
inline void calculate_micro_xs_kernel( double p_energy, int nuc, long n_isotopes,
                           long n_gridpoints,
                           __global const double *  egrid, __global const int *  index_data,
                           __global const NuclideGridPoint *  nuclide_grids,
                           long idx, double *  xs_vector, int grid_type, int hash_bins ){
    // Variables
    double f;
    __global const NuclideGridPoint * low, * high;

    // If using only the nuclide grid, we must perform a binary search
    // to find the energy location in this particular nuclide's grid.
    if (grid_type == 1) { // NUCLIDE
        idx = grid_search_nuclide_kernel(n_gridpoints, p_energy, &nuclide_grids[nuc * n_gridpoints], 0, n_gridpoints - 1);

        if (idx == n_gridpoints - 1)
            low = &nuclide_grids[nuc * n_gridpoints + idx - 1];
        else
            low = &nuclide_grids[nuc * n_gridpoints + idx];
    } else if (grid_type == 0) { // UNIONIZED
        if (index_data[idx * n_isotopes + nuc] == n_gridpoints - 1)
            low = &nuclide_grids[nuc * n_gridpoints + index_data[idx * n_isotopes + nuc] - 1];
        else
            low = &nuclide_grids[nuc * n_gridpoints + index_data[idx * n_isotopes + nuc]];
    } else { // Hash grid
        int u_low = index_data[idx * n_isotopes + nuc];
        int u_high;
        if (idx == hash_bins - 1)
            u_high = n_gridpoints - 1;
        else
            u_high = index_data[(idx + 1) * n_isotopes + nuc] + 1;

        double e_low = nuclide_grids[nuc * n_gridpoints + u_low].energy;
        double e_high = nuclide_grids[nuc * n_gridpoints + u_high].energy;
        int lower;
        if (p_energy <= e_low)
            lower = 0;
        else if (p_energy >= e_high)
            lower = n_gridpoints - 1;
        else
            lower = grid_search_nuclide_kernel(n_gridpoints, p_energy, &nuclide_grids[nuc * n_gridpoints], u_low, u_high);

        if (lower == n_gridpoints - 1)
            low = &nuclide_grids[nuc * n_gridpoints + lower - 1];
        else
            low = &nuclide_grids[nuc * n_gridpoints + lower];
    }

    high = low + 1;

    f = (high->energy - p_energy) / (high->energy - low->energy);

    xs_vector[0] = high->total_xs - f * (high->total_xs - low->total_xs);
    xs_vector[1] = high->elastic_xs - f * (high->elastic_xs - low->elastic_xs);
    xs_vector[2] = high->absorbtion_xs - f * (high->absorbtion_xs - low->absorbtion_xs);
    xs_vector[3] = high->fission_xs - f * (high->fission_xs - low->fission_xs);
    xs_vector[4] = high->nu_fission_xs - f * (high->nu_fission_xs - low->nu_fission_xs);
}

// Calculates macroscopic cross section based on a given material & energy
void calculate_macro_xs_kernel( double p_energy, int mat, long n_isotopes,
                         long n_gridpoints, __global const int *  num_nucs,
                         __global const double *  concs,
                         __global const double *  egrid, __global const int *  index_data,
                         __global const NuclideGridPoint *  nuclide_grids,
                         __global const int *  mats,
                         double *  macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs ){
    int p_nuc;
    long idx = -1;
    double conc;

    for (int k = 0; k < 5; k++)
        macro_xs_vector[k] = 0;

    if (grid_type == 0) { // UNIONIZED
        idx = grid_search_kernel(n_isotopes * n_gridpoints, p_energy, egrid);
    } else if (grid_type == 2) { // HASH
        double du = 1.0 / hash_bins;
        idx = p_energy / du;
    }

    for (int j = 0; j < num_nucs[mat]; j++) {
        double xs_vector[5];
        p_nuc = mats[mat * max_num_nucs + j];
        conc = concs[mat * max_num_nucs + j];
        calculate_micro_xs_kernel(p_energy, p_nuc, n_isotopes,
                                  n_gridpoints, egrid, index_data,
                                  nuclide_grids, idx, xs_vector, grid_type, hash_bins);
        for (int k = 0; k < 5; k++)
            macro_xs_vector[k] += xs_vector[k] * conc;
    }
}

